import{_ as a,o as e,c as n,ag as l}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"Streaming","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/streaming.md","filePath":"capabilities/streaming.md"}'),o={name:"capabilities/streaming.md"};function t(p,s,r,i,c,d){return e(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h1><p>Streaming is LinkedQL&#39;s lazy, pull-based result consumption model. Here, rows are produced only as the consumer requests them (via <code>for await</code>), rather than being pushed all at once.</p><p>Use it when you want:</p><ul><li>row-by-row async iteration</li><li>lower peak memory usage for large result sets</li><li>a query result you can consume on demand instead of buffering all at once</li></ul><p>The API is:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> asyncIterable </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#BABED8;"> asyncIterable) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><p>The surface area is intentionally small:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(query</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> options</span><span style="color:#89DDFF;">?</span><span style="color:#BABED8;">)</span></span></code></pre></div><p>Supported parameters:</p><ul><li><code>query</code>: the query input accepted by the current client, most commonly a SQL string</li><li><code>options.values</code>: positional bind values as with <code>db.query()</code></li><li><code>options.batchSize</code>: number of rows fetched into memory per batch (affects internal buffering, not the one-row-at-a-time iteration interface)</li></ul><p>Example:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> q </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">SELECT id, email FROM public.users WHERE active = $1 ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> asyncIterable </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(q</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#F07178;">  values</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#FF9CAC;">true</span><span style="color:#BABED8;">]</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  batchSize</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 500</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>What this does:</p><ul><li>executes the query once</li><li>exposes the result as an async iterable, consumed incrementally</li></ul><p>Rows are yielded in the order defined by the query (e.g. <code>ORDER BY</code>).</p><h2 id="what-streaming-is-and-is-not" tabindex="-1">What Streaming Is and Is Not <a class="header-anchor" href="#what-streaming-is-and-is-not" aria-label="Permalink to &quot;What Streaming Is and Is Not&quot;">​</a></h2><p>Streaming is:</p><ul><li>lazy</li><li>async-iterable</li><li>still a single query execution</li></ul><p>Streaming is not:</p><ul><li>a live query (results do not update after execution)</li><li>a changefeed (no new rows are observed after the query completes)</li><li>a continuous stream over time</li></ul><p>If you need those, see:</p><ul><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li></ul><h2 id="why-stream" tabindex="-1">Why <code>stream()</code> <a class="header-anchor" href="#why-stream" aria-label="Permalink to &quot;Why \`stream()\`&quot;">​</a></h2><p>Buffered queries are convenient:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.huge_table</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">length)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>But for large results, buffering every row before your code can start consuming them is not always what you want.</p><p>Streaming gives you the right trade there:</p><ul><li>less up-front materialization</li><li>earlier consumption</li><li>simpler handling of large result sets</li></ul><p>Streaming does not change query semantics—it only changes how results are consumed.</p><h2 id="runtime-notes" tabindex="-1">Runtime Notes <a class="header-anchor" href="#runtime-notes" aria-label="Permalink to &quot;Runtime Notes&quot;">​</a></h2><h3 id="mainstream-db-clients" tabindex="-1">Mainstream DB Clients <a class="header-anchor" href="#mainstream-db-clients" aria-label="Permalink to &quot;Mainstream DB Clients&quot;">​</a></h3><p>For <code>PGClient</code>, <code>MySQLClient</code>, and <code>MariaDBClient</code>, <code>stream()</code> maps to the underlying client/runtime&#39;s streaming path.</p><h3 id="edgeclient" tabindex="-1">EdgeClient <a class="header-anchor" href="#edgeclient" aria-label="Permalink to &quot;EdgeClient&quot;">​</a></h3><p><code>EdgeClient</code> can stream over:</p><ul><li>HTTP</li><li>worker ports</li></ul><p>Depending on the <code>portBasedStreaming</code> setting, rows may arrive:</p><ul><li>over a message port</li><li>as a streamed HTTP body parsed incrementally</li></ul><p>By default, <code>portBasedStreaming</code> is set to <code>true</code> – rows are streamed over port even on a HTTP transport. This requires the backend to expose a port-based channel (see <a href="/docs/setup#event-client"><code>event.client</code></a> in <code>EdgeWorker</code>).</p><p>To stream over native HTTP responses, explicitly set <code>portBasedStreaming</code> to <code>false</code> on both <code>EdgeClient</code> and <code>EdgeWorker</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// On the client side</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  portBasedStreaming</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> false</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// On the remote side</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> httpWorkerEdge </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> EdgeWorker</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">httpWorker</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  db</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  portBasedStreaming</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> false</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Regardless of the <code>portBasedStreaming</code> setting, the application-facing shape remains the same async iterable.</p><h3 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h3><p>In FlashQL, <code>stream()</code> gives you lazy iteration over the result of a local query execution.</p><p>That makes it useful for:</p><ul><li>local analytical scans</li><li>browser/worker exports</li><li>large local result sets where full buffering is unnecessary</li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="/docs/query-api">Query Interface</a></li><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li></ul>`,49)])])}const F=a(o,[["render",t]]);export{D as __pageData,F as default};
